    def solve(self, nums, target):
        if target > nums[-1]:
            for i in range(len(nums)-1, -1, -1):
                if nums[i] == target:
                    return True
        elif target < nums[0]:
            for i in range(len(nums)):
                if nums[i] == target:
                    return True
        else:
            left, right = 0, len(nums)-1
            while left <= right:
                mid = (left + right)//2
                if nums[mid] == target:
                    return True
                elif nums[mid] < target:
                    left = mid + 1
                else:
                    right = mid - 1
        return False

